return [
  {
    json: {
      feedUrl: 'http://rsshub:1200/bilibili/user/dynamic/946974?limit=1',
      sourceName: 'Example source',
      sourceType: 'bilibili-dynamic',
      routeToTranscript: false,
      useSpeakerRecognition: false,
      transcriptPollIntervalMs: 0,
      transcriptMaxPolls: 0,
      obsidianInboxDir: '00_Inbox/AI_Information_Processor',
      rss_status: 'success',
      rss_error: '',
      rss_items: [
        {
          title: 'Example latest item',
          guid: 'example-guid-2',
          link: 'https://example.com/post-2',
          isoDate: '2026-04-21T03:00:00.000Z',
          contentSnippet: 'Example latest content.'
        },
        {
          title: 'Example previous item',
          guid: 'example-guid-1',
          link: 'https://example.com/post-1',
          isoDate: '2026-04-20T03:00:00.000Z',
          contentSnippet: 'Example previous content.'
        }
      ]
    }
  }
];

const safeString = (value) => {
  if (value === undefined || value === null) {
    return '';
  }
  return String(value).trim();
};

const toIsoIfPossible = (value) => {
  const text = safeString(value);
  if (!text) {
    return '';
  }
  const date = new Date(text);
  return Number.isNaN(date.getTime()) ? text : date.toISOString();
};

const slugify = (value = '') => safeString(value)
  .normalize('NFKD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-zA-Z0-9\u4e00-\u9fa5]+/g, '-')
  .replace(/^-+|-+$/g, '')
  .toLowerCase();

const stableId = (value = '') => {
  let hash = 5381;
  const text = safeString(value);
  for (let index = 0; index < text.length; index += 1) {
    hash = (((hash << 5) + hash) + text.charCodeAt(index)) >>> 0;
  }
  return hash.toString(16).padStart(8, '0');
};

const buildLatestFingerprint = (item) => ({
  guid: safeString(item?.guid || item?.id || item?.original_id || ''),
  link: safeString(item?.link || item?.canonical_url || ''),
  published_at: toIsoIfPossible(item?.isoDate || item?.pubDate || item?.published_at || ''),
  title: safeString(item?.title || '')
});

const sortItemsNewestFirst = (items) => {
  const fallbackItems = Array.isArray(items) ? items : [];
  return [...fallbackItems].sort((left, right) => {
    const leftRaw = safeString(left?.isoDate || left?.pubDate || left?.published_at || '');
    const rightRaw = safeString(right?.isoDate || right?.pubDate || right?.published_at || '');
    const leftTime = leftRaw ? Date.parse(leftRaw) : Number.NaN;
    const rightTime = rightRaw ? Date.parse(rightRaw) : Number.NaN;
    const leftValid = Number.isFinite(leftTime);
    const rightValid = Number.isFinite(rightTime);
    if (leftValid && rightValid && leftTime !== rightTime) {
      return rightTime - leftTime;
    }
    if (leftValid && !rightValid) {
      return -1;
    }
    if (!leftValid && rightValid) {
      return 1;
    }
    return 0;
  });
};

const passthrough = { ...($json || {}) };
const legacyObsidianInboxDir = safeString(passthrough['obsidian_inbox_dir']);
delete passthrough['obsidian_inbox_dir'];

const sourceName = safeString($json.sourceName || $json.source_name || '');
const sourceType = safeString($json.sourceType || $json.source_type || 'rss') || 'rss';
const feedUrl = safeString($json.feedUrl || $json.feed_url || '');
const routeToTranscript = typeof $json.routeToTranscript === 'boolean'
  ? $json.routeToTranscript
  : (typeof $json.route_to_transcript === 'boolean' ? $json.route_to_transcript : null);
const obsidianInboxDir = safeString($json.obsidianInboxDir || legacyObsidianInboxDir || '00_Inbox/AI_Information_Processor') || '00_Inbox/AI_Information_Processor';
const sourceKey = feedUrl || `${sourceName}::${sourceType}`;
const sourceStateId = stableId(sourceKey || `${sourceName}:${sourceType}`);
const sourceSlug = slugify(sourceName || sourceType || 'source').slice(0, 40) || 'source';
const sourceStatePath = `/home/node/.n8n-files/source_last_seen/${sourceStateId}_${sourceSlug}.json`;
const rssItems = sortItemsNewestFirst($json.rss_items);
const currentLatest = rssItems.length ? buildLatestFingerprint(rssItems[0]) : null;
const sampleTitles = rssItems
  .map((item) => safeString(item?.title || ''))
  .filter(Boolean)
  .slice(0, 5);

return {
  json: {
    ...$json,
    feedUrl,
    sourceName,
    sourceType,
    routeToTranscript,
    useSpeakerRecognition: Boolean($json.useSpeakerRecognition ?? $json.use_speaker_recognition),
    transcriptPollIntervalMs: Number($json.transcriptPollIntervalMs || $json.transcript_poll_interval_ms || 0) || 0,
    transcriptMaxPolls: Number($json.transcriptMaxPolls || $json.transcript_max_polls || 0) || 0,
    obsidianInboxDir,
    rss_status: safeString($json.rss_status || 'success') || 'success',
    rss_error: safeString($json.rss_error || ''),
    rss_items: rssItems,
    source_key: sourceKey,
    source_state_id: sourceStateId,
    source_state_path: sourceStatePath,
    source_item_count: rssItems.length,
    source_sample_titles: sampleTitles,
    source_current_latest: currentLatest
  }
};

const safeString = (value) => {
  if (value === undefined || value === null) {
    return '';
  }
  return String(value).trim();
};

const normalizeLatest = (value) => {
  if (!value || typeof value !== 'object') {
    return null;
  }
  const publishedAt = safeString(value.published_at || value.isoDate || value.pubDate || '');
  const date = publishedAt ? new Date(publishedAt) : null;
  return {
    guid: safeString(value.guid || value.id || ''),
    link: safeString(value.link || value.canonical_url || ''),
    published_at: publishedAt
      ? (Number.isNaN(date?.getTime?.()) ? publishedAt : date.toISOString())
      : '',
    title: safeString(value.title || '')
  };
};

const preparedContext = (() => {
  try {
    return $('Prepare Source Gate Context').item.json || {};
  } catch {
    return {};
  }
})();

let previousState = null;
let readError = '';
if (safeString(preparedContext.rss_status || 'success') !== 'error') {
  if ($binary?.stateData?.data) {
    try {
      const raw = Buffer.from($binary.stateData.data, 'base64').toString('utf8');
      previousState = JSON.parse(raw);
    } catch (error) {
      readError = `parse_failed: ${error.message}`;
    }
  } else if (safeString($json.error || '')) {
    readError = safeString($json.error);
  }
}

return {
  json: {
    ...preparedContext,
    source_previous_state: previousState,
    source_previous_latest: normalizeLatest(previousState?.latest),
    source_state_read_error: readError
  }
};

const safeString = (value) => {
  if (value === undefined || value === null) {
    return '';
  }
  return String(value).trim();
};

const normalizeLatest = (value) => {
  if (!value || typeof value !== 'object') {
    return null;
  }
  return {
    guid: safeString(value.guid || value.id || ''),
    link: safeString(value.link || value.canonical_url || ''),
    published_at: safeString(value.published_at || value.isoDate || value.pubDate || ''),
    title: safeString(value.title || '')
  };
};

const latestMatches = (left, right) => {
  const a = normalizeLatest(left);
  const b = normalizeLatest(right);
  if (!a || !b) {
    return false;
  }
  if (a.guid && b.guid && a.guid === b.guid) {
    return true;
  }
  if (a.link && b.link && a.link === b.link) {
    return true;
  }
  if (a.published_at && b.published_at && a.published_at === b.published_at) {
    if (a.title && b.title) {
      return a.title === b.title;
    }
    return true;
  }
  return false;
};

const previousLatest = normalizeLatest($json.source_previous_latest);
const currentLatest = normalizeLatest($json.source_current_latest);
const rssItems = Array.isArray($json.rss_items) ? $json.rss_items : [];
const rssStatus = safeString($json.rss_status || 'success') || 'success';

let sourceGateStatus = 'changed';
let shouldWriteState = false;
let shouldContinueToProcessing = false;
let newItems = [];

if (rssStatus === 'error') {
  sourceGateStatus = 'rss_error';
} else if (!currentLatest) {
  sourceGateStatus = 'empty';
} else if (previousLatest && latestMatches(currentLatest, previousLatest)) {
  sourceGateStatus = 'unchanged';
} else {
  const matchedPreviousIndex = previousLatest
    ? rssItems.findIndex((item) => latestMatches(item, previousLatest))
    : -1;
  newItems = matchedPreviousIndex >= 0 ? rssItems.slice(0, matchedPreviousIndex) : rssItems;
  sourceGateStatus = newItems.length > 0 ? 'changed' : 'unchanged';
  shouldWriteState = newItems.length > 0;
  shouldContinueToProcessing = newItems.length > 0;
}

const newTitles = newItems
  .map((item) => safeString(item?.title || ''))
  .filter(Boolean)
  .slice(0, 5);
const updatedAt = new Date().toISOString();
const statePayload = currentLatest
  ? {
      source_last_seen_version: 1,
      source_key: safeString($json.source_key || ''),
      feed_url: safeString($json.feedUrl || $json.feed_url || ''),
      source_name: safeString($json.sourceName || $json.source_name || ''),
      source_type: safeString($json.sourceType || $json.source_type || ''),
      latest: currentLatest,
      updated_at: updatedAt
    }
  : null;

return {
  json: {
    ...$json,
    source_previous_latest: previousLatest,
    source_current_latest: currentLatest,
    source_gate_status: sourceGateStatus,
    is_new_since_last_poll: shouldContinueToProcessing,
    should_continue_to_processing: shouldContinueToProcessing,
    source_new_item_count: newItems.length,
    source_new_titles: newTitles,
    rss_items_to_process: newItems,
    source_state_should_write: shouldWriteState,
    source_state_payload: shouldWriteState ? statePayload : null,
    last_seen_recorded_at: shouldWriteState ? updatedAt : safeString($json.source_previous_state?.updated_at || '')
  }
};

const payload = $json.source_state_payload;
if (!payload || typeof payload !== 'object') {
  throw new Error('source_state_payload is required before writing source last-seen state');
}

return {
  json: {
    ...$json
  },
  binary: {
    stateData: {
      data: Buffer.from(JSON.stringify(payload, null, 2), 'utf8').toString('base64'),
      mimeType: 'application/json',
      fileName: `${$json.source_state_id || 'source_last_seen'}.json`,
      fileExtension: 'json'
    }
  }
};

const safeString = (value) => {
  if (value === undefined || value === null) {
    return '';
  }
  return String(value).trim();
};

const toIsoIfPossible = (value) => {
  const text = safeString(value);
  if (!text) {
    return '';
  }
  const date = new Date(text);
  return Number.isNaN(date.getTime()) ? text : date.toISOString();
};

const inputItem = $input.first()?.json || {};

const flattenLatest = (prefix, value) => {
  const latest = value && typeof value === 'object' ? value : {};
  return {
    [`${prefix}_guid`]: safeString(latest.guid || latest.id || ''),
    [`${prefix}_link`]: safeString(latest.link || latest.canonical_url || ''),
    [`${prefix}_published_at`]: toIsoIfPossible(latest.published_at || latest.isoDate || latest.pubDate || ''),
    [`${prefix}_title`]: safeString(latest.title || '')
  };
};

const basePayload = {
  feedUrl: safeString(inputItem.feedUrl || inputItem.feed_url || ''),
  sourceName: safeString(inputItem.sourceName || inputItem.source_name || ''),
  sourceType: safeString(inputItem.sourceType || inputItem.source_type || 'rss') || 'rss',
  routeToTranscript: typeof inputItem.routeToTranscript === 'boolean'
    ? inputItem.routeToTranscript
    : (typeof inputItem.route_to_transcript === 'boolean' ? inputItem.route_to_transcript : null),
  useSpeakerRecognition: Boolean(inputItem.useSpeakerRecognition ?? inputItem.use_speaker_recognition),
  transcriptPollIntervalMs: Number(inputItem.transcriptPollIntervalMs || inputItem.transcript_poll_interval_ms || 0) || 0,
  transcriptMaxPolls: Number(inputItem.transcriptMaxPolls || inputItem.transcript_max_polls || 0) || 0,
  obsidianInboxDir: safeString(inputItem.obsidianInboxDir || inputItem.obsidian_inbox_dir || '00_Inbox/AI_Information_Processor') || '00_Inbox/AI_Information_Processor',
  source_key: safeString(inputItem.source_key || ''),
  source_state_path: safeString(inputItem.source_state_path || ''),
  source_gate_status: safeString(inputItem.source_gate_status || ''),
  is_new_since_last_poll: Boolean(inputItem.is_new_since_last_poll),
  source_item_count: Number(inputItem.source_item_count || 0) || 0,
  source_new_item_count: Number(inputItem.source_new_item_count || 0) || 0,
  source_sample_titles: Array.isArray(inputItem.source_sample_titles) ? inputItem.source_sample_titles.slice(0, 5) : [],
  source_new_titles: Array.isArray(inputItem.source_new_titles) ? inputItem.source_new_titles.slice(0, 5) : [],
  last_seen_recorded_at: safeString(inputItem.last_seen_recorded_at || '')
};

Object.assign(basePayload, flattenLatest('source_previous_latest', inputItem.source_previous_latest));
Object.assign(basePayload, flattenLatest('source_current_latest', inputItem.source_current_latest));

const rssStatus = safeString(inputItem.rss_status || 'success') || 'success';
if (rssStatus === 'error') {
  return [{
    json: {
      ok: false,
      stage: 'rss_read',
      error: safeString(inputItem.rss_error || 'unknown RSS read error') || 'unknown RSS read error',
      should_continue_to_processing: false,
      ...basePayload
    }
  }];
}

if (!inputItem.should_continue_to_processing) {
  return [{
    json: {
      ok: true,
      stage: 'source_last_seen_gate',
      skip_reason: safeString(inputItem.source_gate_status || 'unchanged') || 'unchanged',
      should_continue_to_processing: false,
      ...basePayload
    }
  }];
}

const itemsToProcess = Array.isArray(inputItem.rss_items_to_process) ? inputItem.rss_items_to_process : [];
return itemsToProcess.map((item, index) => ({
  json: {
    ...item,
    ok: true,
    should_continue_to_processing: true,
    source_new_item_index: index + 1,
    source_new_item_total: itemsToProcess.length,
    ...basePayload
  }
}));
